import request from '@/utils/request'

export const profile = {
  // 获取基本信息
  getBasicInfo: () => {
    return request({
      url: '/api/v1/users/profile/basic/',
      method: 'get'
    })
  },

  // 更新基本信息
  updateBasicInfo: (data) => {
    // 如果包含头像字段，使用 FormData
    if (data.avatar && data.avatar instanceof File) {
      const formData = new FormData()
      formData.append('avatar', data.avatar)

      // 添加其他字段
      Object.entries(data).forEach(([key, value]) => {
        if (key !== 'avatar' && value) {
          formData.append(key, value)
        }
      })

      return request({
        url: '/api/v1/users/profile/basic/',
        method: 'post',
        data: formData,
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      })
    }

    // 否则使用普通 JSON
    return request({
      url: '/api/v1/users/profile/basic/',
      method: 'post',
      data
    })
  },

  // 获取详细资料
  getProfile: () => {
    return request({
      url: '/api/v1/users/profile/',
      method: 'get'
    })
  },

  // 更新详细资料
  updateProfile: (data) => {
    return request({
      url: '/api/v1/users/profile/',
      method: 'post',
      data
    })
  },

  // 上传头像
  uploadAvatar: (file) => {
    return new Promise((resolve, reject) => {
      const formData = new FormData()
      formData.append('avatar', file)

      // 添加文件信息日志
      console.log('Uploading avatar:', {
        fileName: file.name,
        fileType: file.type,
        fileSize: file.size,
        formData: Array.from(formData.entries())
      })

      const token = localStorage.getItem('access_token')
      if (!token) {
        return reject(new Error('未找到认证信息'))
      }

      const xhr = new XMLHttpRequest()
      xhr.open('POST', `${process.env.VUE_APP_API_URL}/api/v1/users/profile/avatar/upload/`)

      xhr.setRequestHeader('Authorization', `Bearer ${token}`)

      xhr.onload = () => {
        // 添加原始响应日志
        console.log('Raw response:', {
          status: xhr.status,
          statusText: xhr.statusText,
          responseText: xhr.responseText,
          responseHeaders: xhr.getAllResponseHeaders()
        })

        if (xhr.status === 200) {
          try {
            const response = JSON.parse(xhr.responseText)
            console.log('Parsed response:', response)

            if (response.code === 200 && response.data) {
              resolve({
                code: 200,
                data: {
                  avatar_url: response.data
                },
                message: '上传成功'
              })
            } else {
              console.error('Invalid response structure:', response)
              reject(new Error(response.message || '上传失败'))
            }
          } catch (error) {
            console.error('Parse response error:', {
              error,
              responseText: xhr.responseText
            })
            reject(new Error('解析响应失败'))
          }
        } else {
          console.error('Upload failed:', {
            status: xhr.status,
            statusText: xhr.statusText,
            response: xhr.responseText,
            headers: xhr.getAllResponseHeaders()
          })
          reject(new Error(xhr.statusText || '上传失败'))
        }
      }

      xhr.onerror = () => {
        console.error('Network error:', {
          status: xhr.status,
          statusText: xhr.statusText,
          readyState: xhr.readyState
        })
        reject(new Error('网络错误'))
      }

      xhr.upload.onprogress = (e) => {
        if (e.lengthComputable) {
          const percentComplete = (e.loaded / e.total) * 100
          console.log('Upload progress:', percentComplete + '%')
        }
      }

      xhr.send(formData)
    })
  }
}
